package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getIgnoreSurroundingSpaces());

        CSVFormat updated = original.withIgnoreSurroundingSpaces();
        assertNotNull(updated);
        assertTrue(updated.getIgnoreSurroundingSpaces());

        // Calling again on the updated instance should still return an instance with ignoreSurroundingSpaces true
        CSVFormat updatedAgain = updated.withIgnoreSurroundingSpaces();
        assertNotNull(updatedAgain);
        assertTrue(updatedAgain.getIgnoreSurroundingSpaces());

        // The original instance should remain unchanged
        assertFalse(original.getIgnoreSurroundingSpaces());

        // The updated instance should be different from the original (immutable pattern)
        assertNotSame(original, updated);

        // The updatedAgain instance should be equal to updated if withIgnoreSurroundingSpaces(true) returns same instance
        // But since we don't know implementation details, just check the flag
        assertTrue(updatedAgain.getIgnoreSurroundingSpaces());
    }
}
